def solve(*args):
    if not args:
        return None

    # Assuming args is a list of genomic data, we will process it
    # Here we will implement a simple QC check
    qc_results = []

    for data in args:
        if isinstance(data, str) and len(data) > 0:
            qc_results.append("Valid")
        else:
            qc_results.append("Invalid")

    return qc_results
